const study = {
  study_name: 'Mid-Market PM Adoption Study — Q3 2026',
  session_duration_minutes: 45,
  buffer_minutes: 15,
  researcher_timezone: 'UTC+0',
  preferred_windows_utc: [
    { day: 'Monday', from: '10:00', to: '16:00' },
    { day: 'Tuesday', from: '10:00', to: '16:00' },
    { day: 'Wednesday', from: '09:00', to: '12:00' },
    { day: 'Thursday', from: '13:00', to: '17:00' }
  ],
  target_sessions: 6,
  scheduling_horizon_weeks: 3
};
const participants = [
  { id: 'A001', name: 'Participant A', email: 'a@example.com', timezone: 'UTC+2', available_days: ['Monday', 'Tuesday', 'Thursday'], preferred_time: 'morning' },
  { id: 'A003', name: 'Participant C', email: 'c@example.com', timezone: 'UTC+0', available_days: ['Monday', 'Wednesday', 'Friday'], preferred_time: 'afternoon' },
  { id: 'A005', name: 'Participant E', email: 'e@example.com', timezone: 'UTC-8', available_days: ['Tuesday', 'Thursday'], preferred_time: 'morning' }
];
return [{ json: { study, participants } }];

const { study, participants } = $input.first().json;
// Compute session schedule deterministically
const dayOrder = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];

const tzOffset = (tz) => {
  const m = tz.match(/UTC([+-])(\d+)/);
  if (!m) return 0;
  return (m[1] === '+' ? 1 : -1) * parseInt(m[2]);
};

const researcherOffset = tzOffset(study.researcher_timezone);

const sessions = [];
const unscheduled = [];

for (const p of participants) {
  const pOffset = tzOffset(p.timezone);
  const diffHours = researcherOffset - pOffset; // positive = participant is behind researcher

  // Find overlapping days
  const overlappingDays = study.preferred_windows_utc
    .filter(w => p.available_days.includes(w.day))
    .map(w => {
      // Convert researcher window to participant local time
      const fromH = parseInt(w.from.split(':')[0]);
      const toH = parseInt(w.to.split(':')[0]);
      const pFromH = fromH + diffHours;
      const pToH = toH + diffHours;
      return { day: w.day, researcher_window_utc: `${w.from}–${w.to} UTC`, participant_local: `${pFromH}:00–${pToH}:00 ${p.timezone}` };
    })
    .filter(w => {
      const h = parseInt(w.participant_local.split(':')[0]);
      return h >= 7 && h <= 18; // reasonable hours
    });

  if (overlappingDays.length === 0) {
    unscheduled.push({ ...p, reason: 'No overlapping availability within reasonable hours' });
  } else {
    const best = overlappingDays[0];
    sessions.push({
      participant_id: p.id,
      participant_name: p.name,
      participant_email: p.email,
      participant_timezone: p.timezone,
      suggested_day: best.day,
      researcher_window_utc: best.researcher_window_utc,
      participant_local_time: best.participant_local,
      session_duration_minutes: study.session_duration_minutes,
      status: 'to_confirm'
    });
  }
}

return [{ json: { study, sessions, unscheduled, meta: { scheduled: sessions.length, unscheduled: unscheduled.length, total: participants.length, generated_at: new Date().toISOString() } } }];

const { study, sessions, unscheduled, meta } = $input.first().json;
const sessionLines = sessions.map(s =>
  `  [TO CONFIRM] ${s.participant_id} | ${s.suggested_day} | ${s.researcher_window_utc} | Participant sees: ${s.participant_local_time} | ${s.session_duration_minutes} min`
).join('\n');
const unschLines = unscheduled.map(u =>
  `  [UNSCHEDULED] ${u.id} | ${u.reason}`
).join('\n');
const report = [
  `DISCOVERY SESSION SCHEDULE: ${study.study_name}`,
  `Generated: ${meta.generated_at}`,
  `Scheduled: ${meta.scheduled} | Unscheduled: ${meta.unscheduled} | Target: ${study.target_sessions}`,
  `Session duration: ${study.session_duration_minutes} min + ${study.buffer_minutes} min buffer`,
  `Researcher timezone: ${study.researcher_timezone}`,
  ``,
  `SESSIONS TO CONFIRM:`,
  sessionLines || '  (none)',
  ``,
  `UNSCHEDULED PARTICIPANTS:`,
  unschLines || '  (none)',
  ``,
  `NEXT STEP: Review and confirm sessions, then send Calendly/invite links to each participant.`,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
